import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Dashboard and Reports","description":"","frontmatter":{},"headers":[],"relativePath":"features/dashboard-reports.md","filePath":"features/dashboard-reports.md"}'),i={name:"features/dashboard-reports.md"};function n(s,t,d,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="dashboard-and-reports" tabindex="-1">Dashboard and Reports <a class="header-anchor" href="#dashboard-and-reports" aria-label="Permalink to &quot;Dashboard and Reports&quot;">​</a></h1><p>SendGrail provides a real-time dashboard for quick status checks and a detailed reports page for in-depth analysis of your email delivery performance.</p><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><p>The dashboard is the first screen you see when opening SendGrail. It provides an at-a-glance overview of your email activity.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>If no SMTP connections have been configured, the dashboard automatically redirects to the setup wizard.</p></div><h3 id="stat-cards" tabindex="-1">Stat Cards <a class="header-anchor" href="#stat-cards" aria-label="Permalink to &quot;Stat Cards&quot;">​</a></h3><p>Four summary cards are displayed at the top of the dashboard:</p><table tabindex="0"><thead><tr><th>Card</th><th>Description</th></tr></thead><tbody><tr><td><strong>Total Emails</strong></td><td>Total number of emails processed</td></tr><tr><td><strong>Emails Sent</strong></td><td>Count of successfully delivered emails</td></tr><tr><td><strong>Emails Failed</strong></td><td>Count of failed delivery attempts</td></tr><tr><td><strong>Success Rate</strong></td><td>Percentage of successful deliveries</td></tr></tbody></table><p>Each card includes a <strong>7-day trend arrow</strong> indicating whether the metric is trending up or down compared to the previous period.</p><h3 id="email-volume-chart" tabindex="-1">Email Volume Chart <a class="header-anchor" href="#email-volume-chart" aria-label="Permalink to &quot;Email Volume Chart&quot;">​</a></h3><p>A bar chart showing email volume over time with three selectable ranges:</p><ul><li><strong>7 days</strong> -- Daily breakdown for the past week</li><li><strong>30 days</strong> -- Daily breakdown for the past month</li><li><strong>90 days</strong> -- Daily breakdown for the past quarter</li></ul><h3 id="delivery-breakdown-chart" tabindex="-1">Delivery Breakdown Chart <a class="header-anchor" href="#delivery-breakdown-chart" aria-label="Permalink to &quot;Delivery Breakdown Chart&quot;">​</a></h3><p>A donut chart showing the distribution of email outcomes:</p><ul><li><strong>Sent</strong> -- Successfully delivered</li><li><strong>Failed</strong> -- Delivery failed</li><li><strong>Opened</strong> -- Delivered and opened by recipient (when <a href="/features/open-tracking">open tracking</a> is enabled)</li></ul><h3 id="recent-activity" tabindex="-1">Recent Activity <a class="header-anchor" href="#recent-activity" aria-label="Permalink to &quot;Recent Activity&quot;">​</a></h3><p>A table displaying the <strong>last 10 emails</strong> with key details including recipient, subject, status, and timestamp.</p><h3 id="recent-failures" tabindex="-1">Recent Failures <a class="header-anchor" href="#recent-failures" aria-label="Permalink to &quot;Recent Failures&quot;">​</a></h3><p>A dedicated section listing the <strong>last 5 failed emails</strong> for quick identification of delivery issues. This section helps you spot problems without navigating to the full email log.</p><h2 id="reports-page" tabindex="-1">Reports Page <a class="header-anchor" href="#reports-page" aria-label="Permalink to &quot;Reports Page&quot;">​</a></h2><p>The reports page provides deeper analytics for understanding email performance over time.</p><h3 id="overview-metrics" tabindex="-1">Overview Metrics <a class="header-anchor" href="#overview-metrics" aria-label="Permalink to &quot;Overview Metrics&quot;">​</a></h3><p>A comprehensive set of delivery and engagement metrics:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td><strong>Total</strong></td><td>Total emails processed</td></tr><tr><td><strong>Sent</strong></td><td>Successfully delivered</td></tr><tr><td><strong>Failed</strong></td><td>Failed delivery attempts</td></tr><tr><td><strong>Opened</strong></td><td>Emails opened by recipients</td></tr><tr><td><strong>Clicked</strong></td><td>Emails with at least one link click</td></tr><tr><td><strong>Delivery Rate</strong></td><td>Sent / Total</td></tr><tr><td><strong>Open Rate</strong></td><td>Opened / Sent</td></tr><tr><td><strong>Click Rate</strong></td><td>Clicked / Sent</td></tr><tr><td><strong>Bounce Rate</strong></td><td>Failed / Total</td></tr></tbody></table><h3 id="send-activity-heatmap" tabindex="-1">Send Activity Heatmap <a class="header-anchor" href="#send-activity-heatmap" aria-label="Permalink to &quot;Send Activity Heatmap&quot;">​</a></h3><p>A grid visualization showing email sending patterns over the <strong>last 30 days</strong>:</p><ul><li><strong>Rows</strong>: Days of the week (Monday through Sunday)</li><li><strong>Columns</strong>: Hours of the day (0 through 23)</li><li><strong>Color intensity</strong>: Represents the volume of emails sent during that time slot</li></ul><p>This heatmap helps you understand when your site sends the most email and identify unusual patterns.</p><h3 id="per-connection-performance" tabindex="-1">Per-Connection Performance <a class="header-anchor" href="#per-connection-performance" aria-label="Permalink to &quot;Per-Connection Performance&quot;">​</a></h3><p>A table breaking down performance by individual SMTP connection:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Connection name</td></tr><tr><td><strong>Provider</strong></td><td>SMTP provider</td></tr><tr><td><strong>Total</strong></td><td>Total emails attempted</td></tr><tr><td><strong>Sent</strong></td><td>Successfully delivered</td></tr><tr><td><strong>Failed</strong></td><td>Delivery failures</td></tr><tr><td><strong>Opened</strong></td><td>Emails opened</td></tr><tr><td><strong>Delivery Rate</strong></td><td>Success percentage for this connection</td></tr></tbody></table><p>This view is particularly useful when you have multiple connections and need to compare the reliability and engagement metrics of different providers.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use the per-connection performance table to identify underperforming providers. A connection with a significantly lower delivery rate than others may indicate configuration issues or provider-side problems.</p></div>',33)])])}const g=e(i,[["render",n]]);export{u as __pageData,g as default};
